/* Retrofit overlay — auto-built from recipes/retrofit/batch-*.js.
   Fill-missing standard fields; applied to R (full-cook items share FULL refs). */
window.RETROFIT=Object.assign(window.RETROFIT||{},{"bunny-chow":{"prep":"20 min","cook":"45 min","mistakes":["Not hollowing out the bread enough - you need a deep well for plenty of curry","Undercooking the potatoes - they should be completely tender","Skimping on the aromatics - the ginger-garlic base is essential","Adding water too early - let the spices bloom in oil first","Serving immediately - the flavours need at least 10 minutes to meld"],"sides":["Simple tomato and onion salad","Pickled chillies on the side","Lemon wedges for squeezing","Extra bread chunks for mopping"],"storage":"Keeps for 3 days in the fridge. The bread will soften but the flavour improves. Reheat gently on the stovetop with a splash of water - don't boil or the curry may separate. Store the hollowed loaf separately and assemble when reheating.","chef_upgrade":"Finish with a tempered spice sizzle: fry curry leaves, mustard seeds and dried chillies in oil until aromatic, then pour over the simmering curry. Add a squeeze of fresh lemon juice just before serving for brightness.","health_forward":"Use lean lamb leg instead of knuckles, or swap entirely for skinless chicken thighs. Reduce the oil by half and boost the vegetables with extra carrots, green beans or butternut. Serve with brown rice or a smaller portion of bread on the side.","diets":["highprotein","med"],"diet_notes":"Low-carb: serve over cauliflower rice or steamed greens. Plant-based: use cauliflower or butternut chunks in place of meat, add kidney beans for protein, and use vegetable stock."},"home-chicken-curry":{"health_forward":"Use chicken breast instead of thighs for less fat, or keep thighs and remove the skin. Boost the vegetables with diced peppers, spinach or green beans. Reduce oil to 1 tbsp total and serve with brown rice or extra vegetables instead of bread.","diets":["highprotein","med"],"diet_notes":"Low-carb: serve over cauliflower rice or steamed spinach. Plant-based: replace chicken with chickpeas and cauliflower florets, use coconut yoghurt for creaminess if desired, and add extra vegetables."},"umngqusho":{"prep":"20 min (plus overnight soaking)","cook":"2 hr 30 min","mistakes":["Not soaking overnight - the samp and beans won't soften properly","Adding salt too early - it toughens the beans and slows cooking","Undercooking - the dish should be creamy and porridge-like, not grainy","Skipping the onion aromatics - they add essential sweetness","Not enough liquid - keep adding water as it cooks to prevent sticking"],"sides":["Grilled boerewors or steak","Tomato and onion braai relish","Steamed greens (spinach or cabbage)","Pap or bread to soak up the gravy"],"storage":"Keeps for 4 days in the fridge. The flavours deepen and it freezes beautifully for up to 3 months. Reheat gently with a splash of water or stock - it thickens when cold so thin it out slightly. The texture improves on day 2.","chef_upgrade":"Use homemade beef stock instead of water or shop-bought stock - the depth of flavour transforms the dish. Finish with a knob of butter stirred through just before serving for richness.","health_forward":"Reduce butter to 15 ml and use lean beef stock or vegetable stock. Add more vegetables like diced carrots, celery or spinach. Use half samp and half lentils for extra fibre and protein. Serve with smaller portions of starch and more grilled vegetables.","diets":["highprotein","med","plant"],"diet_notes":"Low-carb: serve as a smaller side portion (100-150g) with grilled meat and plenty of vegetables. Plant-based: use vegetable stock and the butter is optional - coconut oil works too."},"vetkoek":{"prep":"45 min (plus dough rising)","cook":"15 min","sides":["Simple green salad with vinaigrette","Chakalaka or spicy tomato relish","Extra chutney on the side","Pickled onions or atjar"],"storage":"Best eaten immediately while hot and crisp. The dough can be refrigerated overnight after the first rise - let it come to room temperature before shaping and frying. Filled vetkoek can be frozen for up to 1 month - reheat in a 180°C oven for 10-15 minutes to crisp up.","chef_upgrade":"Make your own chutney with dried apricots, peaches and warming spices. Add a splash of vinegar and a pinch of cinnamon for depth. The homemade version balances the rich mince perfectly.","health_forward":"Use lean beef mince (5-10% fat) and reduce oil in the mince filling. Add grated carrots, spinach or peas to boost the vegetables. Use wholemeal flour for half the dough flour for more fibre. Fry in oil at 180°C - hot enough to seal quickly without absorbing excess oil.","diets":["highprotein"],"diet_notes":"Plant-based: replace beef mince with lentils or plant-based mince, use egg replacer in the dough if needed. Low-carb: skip the dough entirely and serve the spiced mince over cauliflower rice or with roasted vegetables."},"beef-teriyaki":{"prep":"15 min (plus marinating)","cook":"10 min","mistakes":["Over-marinating - 30 minutes to 1 hour is plenty, the meat goes mushy","Using lean cuts - you need fat for tender grilled beef","Boiling the sauce - it should simmer gently to thicken","Not slicing against the grain - the meat becomes tough","Crowding the pan - sear in batches for proper browning"],"storage":"Best eaten immediately - the beef dries out when reheated. The sauce can be made ahead and refrigerated for up to 1 week - bring to room temperature before using. Marinated beef can be frozen for up to 3 months - thaw overnight in the fridge.","chef_upgrade":"Make your own teriyaki sauce with equal parts soy sauce, mirin and sake, plus brown sugar. Add fresh ginger, garlic and a splash of rice vinegar. The homemade version has far better depth and balance than bottled sauce.","health_forward":"Use beef sirloin or flank steak instead of rib-eye. Reduce the sugar in the sauce by half and balance with extra vinegar or ginger. Serve with plenty of steamed broccoli, bok choy or green beans. Use reduced-sodium soy sauce.","diets":["highprotein","med"],"diet_notes":"Low-carb: serve over cauliflower rice or zucchini noodles. Plant-based: use firm tofu steaks or tempeh - marinate and grill the same way, though the cooking time will be shorter."},"cacio-e-pepe":{"prep":"5 min","cook":"10 min","sides":["Simple green salad with lemon dressing","Roasted asparagus or broccoli","Crusty bread to mop up the sauce"],"storage":"Best eaten immediately - the emulsified sauce separates when reheated. The cheese can be grated ahead and kept in the fridge for up to 1 week. Leftovers can be refreshed with a splash of hot pasta water and vigorous stirring.","chef_upgrade":"Use aged Pecorino Romano from the wheel - grate it yourself for maximum flavour. Toast the whole peppercorns in a dry pan until fragrant, then crack immediately. The warm spices release oils that transform the dish.","health_forward":"Use half-and-half Pecorino and Parmesan to reduce sodium slightly. Use whole wheat spaghetti for more fibre. Add peas, asparagus or spinach for volume without compromising the classic flavour. Finish with a drizzle of good olive oil instead of extra butter.","diets":["highprotein","med"],"diet_notes":"Low-carb: use zucchini noodles or konjac noodles, though the sauce won't cling the same way. Plant-based: use vegan Pecorino-style cheese or nutritional yeast blended with cashews."},"chicken-satay":{"prep":"30 min (plus marinating)","cook":"15 min","storage":"Marinated chicken keeps for 1 day in the fridge. The sauce can be made ahead and refrigerated for up to 1 week - it thickens when cold, so thin with a little coconut milk or water when reheating. Grilled skewers can be frozen for up to 1 month - thaw and reheat gently.","chef_upgrade":"Make your own peanut sauce from scratch - fry the aromatics (galangal, lemongrass, chillies) before adding coconut milk and peanut butter. Finish with makrut lime leaves and a squeeze of fresh lime juice. The depth of flavour is incomparable to shop-bought sauce.","health_forward":"Use skinless chicken thighs and trim excess fat. Replace some peanut butter with a bit of coconut milk for creaminess with less saturated fat. Use reduced-sugar sweetener or just a little honey. Serve with plenty of cucumber salad and fresh vegetables.","diets":["highprotein","med"],"diet_notes":"Low-carb: skip the peanut sauce or use a smaller portion, serve with extra cucumber and fresh herbs. Plant-based: use firm tofu or tempeh - the marinade works beautifully, and grill for slightly less time."},"chicken-stir-fry":{"health_forward":"Use chicken breast instead of thighs for less fat, or keep thighs and trim visible fat. Boost the vegetables with extra broccoli, snap peas or spinach. Reduce honey to 1 tsp or use a stevia-based sweetener. Serve over cauliflower rice or brown rice instead of white.","diets":["highprotein","med","lowcarb"],"diet_notes":"Plant-based: replace chicken with tofu cubes or tempeh - press and marinate the same way. For extra protein, add edamame or cashews. Low-carb: serve over cauliflower rice or zucchini noodles."},"chicken-tikka-masala":{"prep":"20 min (plus marinating)","cook":"25 min","sides":["Basmati rice","Naan bread or roti","Cucumber raita","Simple tomato and onion salad"],"storage":"Keeps for 3 days in the fridge - the sauce improves as flavours meld. Reheat gently on the stovetop with a splash of water or stock. The sauce freezes beautifully for up to 3 months - freeze without the cream and add fresh cream when reheating.","chef_upgrade":"Marinate the chicken in yoghurt with fresh ginger-garlic paste, lemon juice and garam masala for at least 4 hours or overnight. Grill the chicken over charcoal for authentic smoky flavour before adding to the sauce. The depth of flavour is worth every extra step.","health_forward":"Use chicken breast instead of thighs, or keep thighs and remove the skin. Replace half the cream with Greek yoghurt or coconut milk. Boost the vegetables with spinach, peas or cauliflower. Use brown rice instead of white. Reduce butter to 30 g total.","diets":["highprotein","med"],"diet_notes":"Low-carb: serve over cauliflower rice or with roasted vegetables. Plant-based: use cauliflower or chickpeas instead of chicken, use coconut yoghurt or cashew cream instead of dairy cream."},"crepes":{"prep":"10 min (plus batter resting)","cook":"20 min","sides":["Sweet: Nutella, banana and honey","Savoury: ham and cheese with spinach","Sweet: Lemon and sugar","Savoury: smoked salmon and cream cheese"],"storage":"Batter keeps for 1 day in the fridge - the flour may settle, so whisk well before cooking. Cooked crepes can be stacked with baking paper and frozen for up to 1 month - thaw and reheat in a dry pan. Best eaten fresh but reheating works well.","chef_upgrade":"Infuse the milk with a vanilla bean or orange zest before making the batter. Strain after 30 minutes for subtle fragrance. For a richer crepe, replace half the milk with buttermilk or add an extra egg yolk.","health_forward":"Use whole wheat flour for half the flour for more fibre. Replace some milk with water for lighter crepes. Reduce sugar to 1 tsp or skip for savoury versions. Fill with plenty of fresh fruit and Greek yoghurt instead of sugary toppings.","diets":["med","highprotein"],"diet_notes":"Plant-based: use plant milk (oat or soy works well), replace eggs with flax egg or commercial egg replacer. Low-carb: use almond flour or coconut flour instead of wheat flour, though the texture will differ."},"croissants":{"prep":"45 min","cook":"25 min","mistakes":["Butter too soft and leaking during lamination","Dough tears when rolling out layers","Underproving - dense, bready texture","Overbaking - too dark, dry interior","Not chilling between folds - butter melts through"],"storage":"Best fresh the day they're made. Freeze unbaked after shaping; bake from frozen at 200°C for 25 min. Leftovers keep 2 days in a paper bag - refresh 5 min at 180°C.","chef_upgrade":"Use cultured butter (82% fat) for deeper flavour. Brush with simple syrup (1:1 water:sugar) after baking for a glossy, professional finish.","health_forward":"Replace 30% of white flour with wholegrain for fibre and nuttiness. Use cultured butter for probiotic benefits - same lamination quality.","diets":["med"],"diet_notes":"Low-carb: not suitable - laminated dough relies on flour. Plant-based: use plant-based butter block (must be 82% fat minimum for lamination).","sides":["Butter and jam","Strong coffee or tea","Fresh fruit","Scrambled eggs"]},"egg-fried-rice":{"health_forward":"Add 60 g frozen peas or mixed veg for fibre. Use brown rice for whole grains. Swap 1 egg for 120 g firm tofu cubes, added with the rice, for plant-based protein.","diets":["med","highprotein"],"diet_notes":"Plant-based: scramble 150 g firm tofu instead of eggs; add 1 tbsp nutritional yeast with soy sauce for savoury depth. Low-carb: use cauliflower rice (about 250 g riced cauliflower)."},"falafel-plate":{"prep":"20 min","cook":"15 min","mistakes":["Mixture too wet - falls apart in oil","Not enough chickpeas - dense, mealy texture","Oil too cold - greasy, undercooked","Overprocessing - gummy paste, not light","Skipping baking soda - tough, dry centres"],"sides":["Warm pita bread","Pickled vegetables (turnips, cucumber)","Israeli salad (diced tomato, cucumber, parsley)","Lemon wedges"],"storage":"Uncooked falafel mixture keeps 2 days refrigerated; shape and fry from chilled. Fried falafel keeps 3 days - reheat at 180°C for 8 min to crisp. Freeze uncooked balls on a tray, then bag; fry from frozen (add 2 min).","chef_upgrade":"Soak chickpeas with 1 tsp baking soda - tenderises without boiling. Add 2 tsp dried mint or za'atar to the mixture. Serve with amba (fermented mango sauce) alongside tahini.","health_forward":"Bake at 200°C for 25 min instead of frying (brush with 2 tbsp oil). Add 60 g spinach to the mixture for micronutrients. Use baked sweet potato wedges instead of pita.","diets":["med","plant","highprotein"],"diet_notes":"Low-carb: serve over salad greens instead of pita; add 120 g grilled chicken or halloumi. High-protein: serve with 2 hard-boiled eggs or Greek yoghurt."},"flapjacks-pancakes":{"prep":"10 min","cook":"15 min","mistakes":["Overmixing - tough, rubbery pancakes","Griddle too hot - burnt outside, raw inside","Batter too thick - doughy centres","Flipping too early - break apart","Not resting batter - dense texture"],"storage":"Batter keeps 24 hours refrigerated (may thin slightly - add 1 tbsp flour). Cooked pancakes freeze well layered with baking paper - reheat in toaster or 180°C oven for 5 min.","chef_upgrade":"Separate eggs, whip whites to soft peaks, fold through at the end for cloud-like texture. Add 60 g blueberries or chocolate chips to each pancake just before flipping.","health_forward":"Replace half white flour with wholegrain. Swap buttermilk for plain yoghurt (thinned with 60 ml milk) for protein and probiotics. Use fruit compote instead of full-sugar syrup.","diets":["med","highprotein"],"diet_notes":"Plant-based: use 250 ml plant-based milk plus 1 tbsp apple cider vinegar for buttermilk; replace egg with 60 g mashed banana. Low-carb: use almond flour and egg whites only - no buttermilk.","sides":["Maple syrup or honey","Crispy streaky bacon","Fresh berries and banana","Lemon wedges and caster sugar"]},"gemista-stuffed-peppers-aubergine":{"prep":"25 min","cook":"45 min","mistakes":["Undercooked vegetables - tough skins","Overstuffing - split during baking","Not covering - dry filling","Skipping oil - bland, sticks to dish","Underseasoning rice - bland stuffing"],"storage":"Keeps 4 days refrigerated. Reheat at 180°C for 15-20 min, covered with foil. Freezes well - cool completely, wrap individually, freeze up to 3 months. Thaw overnight before reheating.","chef_upgrade":"Add 60 g pine nuts or walnuts to the filling for crunch. Use fresh dill and mint in the rice mixture. Finish with 120 g crumbled feta over the last 10 min of baking.","health_forward":"Use brown rice for fibre. Replace half rice with quinoa for complete protein. Add 120 g grated courgette to the filling for hidden veg. Use less oil (3 tbsp) - the vegetables release moisture.","diets":["med","plant"],"diet_notes":"High-protein: add 120 g crumbled feta or halloumi to the filling. Low-carb: replace rice with cauliflower rice (use about 375 g riced cauliflower) - bake 30 min."},"macaroni-cheese":{"prep":"15 min","cook":"20 min","sides":["Garlic bread","Green salad with vinaigrette","Roasted butternut","Steamed broccoli with lemon"],"storage":"Sauce keeps 3 days; pasta absorbs sauce - add 60 ml milk when reheating. Freeze assembled unbaked for up to 2 months; bake from frozen at 180°C for 45 min (cover with foil for first 30 min).","chef_upgrade":"Make a quick roux-based cheese sauce with 60 g flour, 60 g butter, 1 L milk - smoother than flour-into-milk. Add 120 g grated mozzarella for stretch. Top with 60 g grated Parmesan and paprika.","health_forward":"Use 50:50 wholegrain and white pasta. Replace half cheese sauce with pureed butternut or cauliflower (blend with the sauce). Add 60 g frozen spinach to the sauce. Use 3 tbsp butter and less flour (45 g) for lighter roux.","diets":["med","highprotein"],"diet_notes":"Plant-based: use plant-based cheese and milk; add 60 g nutritional yeast for savoury depth. Low-carb: use cauliflower florets instead of pasta - steam 10 min before baking with sauce."},"penne-arrabbiata":{"health_forward":"Add 120 g baby spinach to the sauce in the last 2 min. Use wholegrain penne for fibre. Reduce oil to 3 tbsp - the garlic and chilli carry flavour. Serve with 60 g grated Parmesan for protein.","diets":["med","plant"],"diet_notes":"High-protein: add 120 g tinned chickpeas (rinsed) or grilled chicken strips. Low-carb: serve over zucchini noodles (2 large courgettes, spiralised) instead of pasta - simmer sauce 3 min before tossing."},"prego-roll":{"health_forward":"Use lean rump or sirloin, trim visible fat. Swap 1 tbsp butter for 30 g avocado in the garlic spread. Add 60 g rocket or watercress to the roll for greens. Use wholegrain rolls if available.","diets":["med","highprotein"],"diet_notes":"Plant-based: use 200 g grilled portobello steak or thick tofu steaks; season with steak spice and sear 3 min per side. Low-carb: serve in lettuce cups or over salad with the peri-peri butter drizzled over."},"quesadillas":{"prep":"10 min","cook":"10 min","mistakes":["Pan too hot - burnt tortilla, cold cheese","Too much filling - splits when folding","Not pressing down - unmelted cheese","Using low-moisture cheese - grainy texture","Soggy tortilla - moisture from veg"],"storage":"Assembled quesadillas keep 1 day refrigerated. Reheat in a dry pan to re-crisp. Freeze cooked quesadillas between baking paper - reheat in a 200°C oven for 8 min.","chef_upgrade":"Make a quick pico de gallo (diced tomato, onion, coriander, lime) to serve alongside. Add 60 g roasted poblano peppers or jalapenos to the cheese. Use cotija or feta for salty finish.","health_forward":"Use 50:50 white and wholegrain tortillas. Add 60 g black beans, 60 g corn, and 60 g spinach to the cheese. Use 120 g cheese total instead of 180 g - stretch with veg. Serve with guacamole for healthy fats.","diets":["med","plant","highprotein"],"diet_notes":"High-protein: add 120 g shredded chicken or 90 g prawns. Low-carb: use large lettuce leaves or low-carb tortillas instead of flour tortillas."},"quiche-lorraine":{"prep":"25 min","cook":"35 min","mistakes":["Soggy bottom - underbaked pastry","Overbaked - curdled, watery filling","Too much egg - rubbery texture","Not chilling pastry - shrinks during baking","Overfilling - spills over, uneven baking"],"sides":["Green salad with mustard vinaigrette","Roasted baby potatoes","Asparagus with lemon","Fresh baguette"],"storage":"Quiche keeps 3 days refrigerated. Reheat at 160°C for 15 min. Freezes well unbaked - wrap tightly, freeze up to 2 months; bake from frozen at 180°C for 50-60 min (cover edges with foil if browning too fast).","chef_upgrade":"Make pastry with 180 g flour, 90 g cold butter, 2 egg yolks - richer and shorter. Blind-bake with baking beans for 12 min at 200°C. Add 120 g Gruyère plus 60 g Parmesan for depth. Serve with cornichons.","health_forward":"Use 50:50 wholegrain and white flour for pastry. Replace 120 ml cream with milk. Add 120 g spinach or 60 g broccoli to the filling. Use 120 g cheese total instead of 180 g - stretch with veg.","diets":["med","highprotein"],"diet_notes":"Plant-based: use plant-based bacon pieces or 90 g smoked tofu; replace eggs with 180 g silken tofu blended with 120 ml plant-based milk and 1 tbsp cornflour. Low-carb: use crustless quiche - bake filling directly in a greased dish for 30 min."},"shakshuka-crusty-bread":{"prep":"15 min","cook":"20 min","mistakes":["Overcooking eggs until yolks are fully set","Under-seasoning the tomato base","Not using enough oil to carry the spices","Skipping the herb finish - parsley and mint are essential"],"storage":"Keeps 2 days in the fridge; reheat gently in a pan covered with a lid - the eggs will continue cooking, so stop just before they look done","health_forward":"Use a mixture of whole eggs and extra whites for higher protein; add diced baby spinach or kale when wilting the onions for extra veg","diets":["med","highprotein"],"diet_notes":"Low-carb: skip the bread and serve with a side of sauteed mushrooms. Plant-forward: swap eggs for chickpeas or white beans, adding them when the tomatoes are softened.","chef_upgrade":"Bake in individual cast-iron skillets for tableside theatre; crumble feta and dukkah over the top, finish with a drizzle of chilli oil, and serve with warm sourdough rubbed with garlic to soak up every drop of sauce."},"smash-burgers-special-sauce":{"cook":"8 min","sides":["Crisp shoestring fries","Gherkin and tomato salad","Artisanal coleslaw"],"storage":"Eat immediately - smashed burgers don't reheat well. Patty meat can be shaped and frozen raw for up to a month; cook from frozen on medium heat","chef_upgrade":"Dry-age the beef mince for 3 days in the fridge uncovered for deeper umami, or blend in 20% short rib for extra richness","health_forward":"Use lean beef mince (90/10) and compensate with an extra dash of olive oil; swap mayo for greek yoghurt in the special sauce; wrap in large lettuce leaves instead of buns","diets":["highprotein"],"diet_notes":"Low-carb: use lettuce cups or portobello mushroom caps as buns. Plant-forward: impossible patties or thick portobello caps smashed on the griddle work remarkably well"},"spaghetti-bolognese":{"health_forward":"Boost vegetables by grating carrot and zucchini directly into the simmering sauce - they melt away; use lean beef mince and finish with olive oil rather than milk for creaminess","diets":["med","highprotein"],"diet_notes":"Low-carb: serve over zucchini noodles or steamed broccoli. Plant-forward: use minced mushrooms or plant-based mince - the soffrito and slow-cooked technique carry the dish regardless of protein"},"carbonara":{"prep":"10 min","cook":"12 min","sides":["Simple green salad with lemon vinaigrette","Crusty baguette"],"storage":"Eat immediately - reheated carbonara separates and becomes grainy. Uncooked egg mixture can be refrigerated 1 day; toss through hot pasta with a splash of pasta water to emulsify","chef_upgrade":"Make your own guanciale from pork belly cured with salt, pepper, thyme and juniper for 5 days - or use proper aged guanciale from an Italian deli","health_forward":"Use a higher ratio of yolks to whites (3 yolks to 1 whole egg) for richer sauce with less cholesterol impact; shave courgette into ribbons and toss through for volume","diets":["highprotein"],"diet_notes":"Low-carb: serve over zucchini noodles or steamed asparagus. Plant-forward: smoked tofu cubes and nutritional yeast can approximate the smoky-salty punch - not traditional but satisfying"},"spanakopita":{"prep":"40 min","cook":"45 min","mistakes":["Not squeezing excess moisture from spinach - soggy filling is fatal","Using oil spray instead of brushing melted butter between layers","Overfilling the phyllo so it bursts during baking","Not covering with damp cloth - phyllo dries out in minutes","Serving immediately - needs 15 minutes rest to set"],"sides":["Greek salad with feta and kalamata olives","Lemon-roasted baby potatoes"],"storage":"Keeps 3 days refrigerated; recrisp in a 180C oven for 10 minutes. Freezes beautifully unbaked - wrap tightly in foil and bake from frozen at 180C for 50 minutes","chef_upgrade":"Use proper Greek feta in brine - barrel-aged for extra tang; add wild leek or ramps if you can find them; brush top layers with clarified butter for extra golden crisp","health_forward":"Reduce feta slightly and boost spinach; use olive oil instead of butter - still delicious; add chopped dill and mint for more herb volume","diets":["med","plant"],"diet_notes":"Gluten-free: this dish needs phyllo - not suitable. Plant-forward: already naturally plant-based if using vegan feta or nutritional yeast - the phyllo and spinach carry the dish"},"thai-green-curry":{"prep":"15 min","cook":"25 min","sides":["Jasmine rice or steamed sticky rice","Cucumber salad with rice vinegar","Fried tofu pieces"],"storage":"Keeps 3 days - flavours improve overnight. Reheat gently without boiling or the coconut milk will split. Freezes well for 1 month - thaw completely before reheating","health_forward":"Use light coconut milk and boost aromatics; add baby corn, snow peas and bamboo shoots for more vegetable volume; finish with fresh lime juice instead of palm sugar","diets":["highprotein"],"diet_notes":"Low-carb: serve over cauliflower rice or steamed vegetables. Plant-forward: use tofu puffs or young green jackfruit - both absorb curry beautifully; shrimp paste can be swapped for fermented soybean paste","chef_upgrade":"Pound the green curry paste fresh in a mortar for a vivid, layered flavour the jar cannot match; infuse the first thick coconut cream with bruised lemongrass and makrut lime leaf before splitting the oil; finish with deep-fried crispy shallots and torn Thai basil for a glossy, restaurant-grade curry."},"french-onion-soup":{"prep":"15 min","cook":"1 hr 20 min","sides":["Mixed green salad with sharp vinaigrette","Additional toasted baguette with butter"],"storage":"Keeps 4 days - the flavour deepens. Reheat slowly; add a splash of water if reduced too far. Gruyere croutons don't store well - make fresh. Soup base freezes 2 months","chef_upgrade":"Make your own beef stock from roasted marrow bones for depth; use three types of onion - yellow, red and shallots - for complexity; finish the soup with a splash of cognac before serving","health_forward":"Use half butter half olive oil; add shredded kale or spinach during the last 10 minutes; serve with less cheese and more fresh thyme","diets":["med","highprotein"],"diet_notes":"Low-carb: skip the crouton or use a thin slice of wholegrain toast. Plant-forward: use mushroom stock or a rich vegetable stock made with roasted roots and tomato paste - umami remains strong"},"churros-chocolate":{"prep":"20 min","cook":"10 min","mistakes":["Oil not hot enough - soggy, greasy churros","Oil too hot - burnt outside, raw dough inside","Overmixing the dough - tough rather than tender","Not piping straight into hot oil - batter spreads and loses shape","Rolling in sugar too early - falls off when cooled"],"sides":["Fresh berries or sliced oranges","Strong coffee or thick hot chocolate"],"storage":"Eat within hours - they lose crispness rapidly. Unfried dough can be piped onto baking sheets and frozen - fry from frozen in 170C oil for 4 minutes. Chocolate sauce keeps 5 days refrigerated; reheat gently","health_forward":"Use wholemeal flour for extra fibre - the chocolate hides any earthiness; reduce sugar coating by half and cinnamon dusting for flavour without sweetness; offer fruit alongside for natural sweetness","diets":["med"],"diet_notes":"Not suitable for low-carb or plant-forward. Gluten-free: use a proper GF flour blend with xanthan gum - the texture won't be identical but still crisp","chef_upgrade":"Rest the choux dough 15 minutes before frying for a lighter, crisper churro; hold the oil at 175°C with a thermometer for an even, blister-free crust, and infuse the dipping chocolate with a cinnamon stick and a shot of espresso."},"bobotie":{"prep":"25 min","cook":"50 min","sides":["Yellow rice with turmeric and raisins","Steamed green beans or baby marrow","Sambals of tomato and onion","Chutney or blatjang"],"storage":"Keeps 4 days - flavours meld beautifully. Reheat covered at 160C for 20 minutes; add a splash of water if the custard is drying. Freezes well for 2 months - thaw completely before reheating","chef_upgrade":"Soak the bread in full-cream milk and squeeze dry - adds creaminess; use freshly toasted and ground curry powder for intensity; top with caramelised banana slices under the custard for true Cape Malay flair","health_forward":"Use lean beef mince and add more diced apple and apricot for sweetness; reduce sugar and boost turmeric and ginger for warmth; serve with extra vegetables on the side","diets":["highprotein"],"diet_notes":"Low-carb: skip the rice and serve over roasted butternut or steamed cauliflower. Plant-forward: use lentils or plant-based mince - the Cape Malay spices carry the dish completely"},"breyani":{"prep":"40 min","cook":"1 hr 20 min","mistakes":["Not rinsing rice until the water runs clear - starch makes grains sticky and mushy","Not sealing the pot properly - steam escapes and rice stays undercooked","Opening the lid too often - loses critical steam","Using converted rice instead of basmati - wrong texture entirely","Cooking on high heat - bottom burns and top remains raw"],"sides":["Cucumber yoghurt raita","Sambals of tomato and onion","Hard-boiled eggs","Fried onions (beresta) for crunch"],"storage":"Keeps 4 days - the spices intensify. Reheat with a splash of water covered in the oven at 160°C. Freezes well for 2 months - thaw completely and reheat slowly. Rice hardens slightly when frozen but remains edible","chef_upgrade":"Marinate meat in yoghurt and spices overnight for deep flavour penetration; use saffron-infused milk for the top rice layer - visual luxury and fragrance; finish with fried onions (beresta) for crunch","health_forward":"Use brown basmati for extra fibre - needs 20 minutes more cooking liquid; trim visible fat from meat; add more vegetables like cauliflower florets or green beans between layers","diets":["highprotein"],"diet_notes":"Low-carb: use cauliflower rice instead of basmati - steam separately and fold through spiced meat. Plant-forward: use firm vegetables like baby marrow, aubergine and cauliflower instead of meat - the layered technique and spice blend carry the dish"},"cape-malay-chicken-curry":{"prep":"20 min","cook":"55 min","mistakes":["skipping toasting whole spices - they taste flat and harsh","burning the masala - if spices darken past golden, start over","adding potatoes too early - they dissolve before chicken cooks","skimping on apricot jam - the signature sweetness is lost","under-reducing the gravy - should be thick and coating"],"sides":["yellow rice with raisins","sambals of tomato and onion","roti or plain naan","chunky atjar"],"storage":"keeps 3 days refrigerated; reheat gently with a splash of water to loosen the gravy. freezes well for 2 months - thaw completely before reheating.","chef_upgrade":"finish each portion with a dollop of ghee and a pinch of garam masala - the fat carries spice aromatics and the fresh spice dust lifts the entire dish.","health_forward":"swap chicken thighs for breast, use skinless pieces, and reduce oil to 1 tsp. add about 300 g chopped butternut and baby marrow with the potato - the vegetables bulk out the curry and soak up the same spiced gravy for a lighter but still flavourful bowl.","diets":["med","highprotein"],"diet_notes":"low-carb: serve over cauliflower rice or steamed greens instead of roti. plant: use extra-firm tofu cubes or chickpeas - adjust cooking time and add with the potatoes."},"denningvleis":{"prep":"25 min","cook":"1 hr 5 min","mistakes":["using lean lamb - the dish needs fat for melting tenderness","skipping the vinegar bloom - the tamarind must simmer to mellow","oversalting - the dried fruit and spices concentrate; salt lightly","rushing the braise - lamb needs slow, covered simmering","skimping on cinnamon - it's the backbone of the flavour"],"sides":["yellow rice with raisins","boiled green beans with butter","chunky tomato sambal","spiced roasted sweet potato"],"storage":"keeps 4 days refrigerated; the flavour deepens daily. reheat gently with a splash of water or stock. freezes well for 3 months.","chef_upgrade":"use a quality maldive fish (dried fish) infusion - rehydrate a small piece in the vinegar, then simmer it with the aromatics for that authentic umami depth.","health_forward":"trim excess fat from lamb, use shoulder over neck, and add about 300 g diced butternut or pumpkin - the fruit sweetness mirrors the dried apricots while boosting fibre and reducing meat per portion.","diets":["med","highprotein"],"diet_notes":"low-carb: serve over steamed cauliflower rice with extra coriander. plant: use beef or lamb-style seitan chunks or portobello mushrooms - adjust braise time to 35-40 minutes."},"doro-wat":{"prep":"30 min","cook":"1 hr 30 min","mistakes":["burning the berbere - it turns bitter and harsh","skimming the foam - the red oil (kibbeh) is essential","overcooking eggs - they should be just set through","using mild paprika - real berbere packs heat","undersalting - the spiced butter and eggs need balance"],"sides":["injera (traditional)","flatbread or roti","spiced cabbage and potatoes","simple tomato salad"],"storage":"keeps 3 days refrigerated; reheat gently and avoid boiling the eggs again. freezes well without eggs for 2 months - add fresh eggs when reheating.","chef_upgrade":"finish with niter kibbeh (spiced clarified butter) - infuse butter with cardamom, cinnamon and cloves, then drizzle over each portion for that signature aromatic richness.","health_forward":"use chicken breast instead of thighs, trim all visible fat, and reduce oil to 1 tbsp. load the sauce with extra tomatoes and onions - they create body without cream or butter.","diets":["med","highprotein"],"diet_notes":"low-carb: serve over cauliflower rice or with extra steamed vegetables. plant: use tofu cubes or chickpeas - simmer for 45 minutes and adjust berbere to taste."},"durban-mutton-curry":{"prep":"30 min","cook":"1 hr","mistakes":["using precooked curry powder - it lacks punch","skipping the curry leaves - they're essential to Durban style","underseasoning the meat - salt and oil the mutton before searing","adding water too early - let the masala darken first","undersalting - the spices need salt to bloom"],"sides":["yellow rice with sultanas","roti or plain naan","chunky tomato and onion sambal","cucumber raita"],"storage":"keeps 4 days refrigerated; the flavour improves. reheat gently with a splash of water. freezes well for 3 months - thaw completely before reheating.","chef_upgrade":"finish each portion with a squeeze of fresh lime and a sprinkle of garam masala - the acid brightens the rich gravy and the fresh spice dust lifts the aromatic intensity.","health_forward":"use lean mutton pieces, trim visible fat, and reduce oil to 2 tbsp. add about 300 g chopped butternut and baby marrow - they absorb the same spiced gravy for a lighter bowl.","diets":["med","highprotein"],"diet_notes":"low-carb: serve over cauliflower rice or steamed spinach. plant: use lamb-style seitan or mushrooms - adjust braise time to 45 minutes and add extra curry leaves."},"hertzoggies":{"prep":"30 min","cook":"30 min","mistakes":["overbaking the pastry shells - they should be pale golden, not brown","skipping pastry docking - blind bake with weights to prevent puffing","overwhipping meringue - it weeps and collapses","underbaking meringue - it must be dry to the touch","skimming on coconut - it provides the signature texture"],"sides":["filter coffee","rooibos tea","fresh berries","vanilla ice cream"],"storage":"keeps 2 days at room temperature in an airtight container - the meringue softens. best fresh. refrigerate after 24 hours in humid weather.","chef_upgrade":"use homemade apricot jam - simmer dried apricots with water and sugar until thick, then brush over pastry while warm for a set, glossy glaze.","health_forward":"swap butter for coconut oil in the pastry, use a whole wheat spelt flour blend, and reduce sugar in the meringue by a third - the coconut and jam provide natural sweetness.","diets":[],"diet_notes":"not suitable for low-carb or plant-based diets as written. for lighter treats, try fresh fruit pavlova or baked apricot parcels."},"melktert":{"prep":"25 min","cook":"40 min","mistakes":["overbaking the crust - it should be pale, not golden","skipping crust docking - blind bake thoroughly to prevent sogginess","overcooking custard - it should wobble like jelly","skipping cinnamon dusting - it's essential to the flavour","rush chilling - the custard needs 4 hours to set properly"],"sides":["filter coffee","rooibos tea","fresh berries","light fruit salad"],"storage":"keeps 3 days refrigerated - the crust softens but flavour holds. best within 24 hours for crisp crust. do not freeze - the custard separates.","chef_upgrade":"infuse the milk with a vanilla pod and cinnamon stick overnight - strain and use in the custard for a deep, aromatic complexity.","health_forward":"use a 50:50 blend of full-cream and low-fat milk, swap the biscuit crust for a whole wheat digestive crust, and reduce sugar by 25% - the cinnamon provides sweetness.","diets":[],"diet_notes":"not suitable for low-carb or plant-based diets. for lighter desserts, try baked custard in ramekins or milk-free fruit tarts."},"peppermint-crisp-tart":{"prep":"20 min","cook":"0 min","mistakes":["underchilling - the tart needs 6 hours to set properly","overwhipping cream - it curdles when folded","skipping the caramel layer - it's the essential binder","using cheap biscuits - they turn soggy fast","oversweetening - the condensed milk and biscuit are already sweet"],"sides":["filter coffee","rooibos tea","fresh strawberries","plain vanilla yoghurt"],"storage":"keeps 3 days refrigerated - the biscuit softens but flavour holds. do not freeze - the texture separates. serve cold.","chef_upgrade":"use homemade caramel - simmer condensed milk with butter and golden syrup until thick, then cool before layering for a deeper, less cloying caramel.","health_forward":"swap condensed milk for a blend of cream cheese and Greek yoghurt sweetened with honey, use dark chocolate digestive biscuits, and reduce Peppermint Crisp to 1 bar - the mint provides the same lift.","diets":[],"diet_notes":"not suitable for low-carb or plant-based diets. for lighter treats, try fresh berry parfaits or yoghurt-based mousse tarts."},"pickled-fish":{"prep":"20 min","cook":"25 min","mistakes":["overcooking fish - it should be just flaked, not mushy","skipping the curry bloom - spices must fry in oil","undersalting - the vinegar needs salt to balance","rushing the pickle - fish needs 24 hours minimum","using lean fish - oilier fish holds up better to vinegar"],"sides":["hot cross buns (traditional)","brown bread and butter","boiled potatoes","chunky tomato sambal"],"storage":"keeps 5 days refrigerated in the pickle liquid - the flavour deepens. do not freeze - the texture degrades.","chef_upgrade":"use homemade fish curry powder - toast coriander, cumin, mustard seeds and turmeric, then grind fresh for a brighter, more aromatic pickle.","health_forward":"reduce oil to 2 tbsp for frying, use white wine vinegar instead of brown, and increase onion and coriander - the aromatics provide bulk without oil.","diets":["med","highprotein"],"diet_notes":"low-carb: serve with extra sambals and skip bread. plant: use firm tofu cubes or cauliflower florets - adjust pickling time to 48 hours."},"shisa-nyama":{"prep":"40 min","cook":"1 hr 20 min","mistakes":["undermarinating meat - flavours need 2 hours minimum","overcrowding the braai - meat steams instead of grilling","skipping rest time - juices need 5 minutes to redistribute","oversaucing - peri-peri burns easily; apply at the end","using lean cuts only - fat prevents drying over coals"],"sides":["pap and tomato gravy","roasted mielie (corn on the cob)","chunky tomato and onion sambal","coleslaw with vinaigrette"],"storage":"grilled meat keeps 3 days refrigerated - reheat gently. do not freeze - texture suffers. marinate raw meat up to 24 hours.","chef_upgrade":"finish with a compound butter - blend butter with garlic, parsley and a squeeze of lemon, then melt over rested meat for restaurant-quality sheen and flavour.","health_forward":"trim visible fat from all cuts, use skinless chicken, and load up on vegetable sides. swap boerewors for lean beef or chicken wors - reduce oil in marinades to 1 tbsp per 500g.","diets":["med","highprotein"],"diet_notes":"low-carb: skip pap and serve with double sambals and grilled vegetables. plant: use grilled portobello mushrooms, maize cobs, and vegetable skewers - adjust marinade time to 30 minutes."},"butter-chicken":{"prep":"25 min","cook":"35 min","mistakes":["undermarinating chicken - it needs 2 hours minimum for tenderisation","burning the tomato base - if it darkens, start over","overspicing the sauce - let the cream carry flavour","skimming the red oil - it's essential to the makhani sauce","using sweet curry powder - it clashes with the tomato base"],"sides":["basmati rice","naan or roti","chunky cucumber raita","spiced roasted cauliflower"],"storage":"keeps 3 days refrigerated; reheat gently with a splash of cream or water. freezes well for 2 months - thaw completely before reheating.","chef_upgrade":"finish with kasuri methi (dried fenugreek) crushed between your palms - the herb's bitter-sweet complexity lifts the creamy sauce into restaurant territory.","health_forward":"use chicken breast instead of thighs, trim all fat, and reduce oil to 1 tsp. load the sauce with extra tomatoes and onions - they create body without butter. swap half the cream for Greek yoghurt.","diets":["med","highprotein"],"diet_notes":"low-carb: serve over cauliflower rice or steamed greens. plant: use tofu cubes or chickpeas - simmer for 30 minutes and adjust garam masala to taste."},"carnitas-tacos":{"prep":"40 min","cook":"3 hr","mistakes":["Not drying pork thoroughly before rendering - meat stews instead of fries","Skipping the crisp-up at the end - carnitas need that browned crunch","Using lean pork only - fat is essential for authentic texture","Overcrowding the pan for crisping - meat steams instead of caramelises"],"sides":["Mexican rice","Refried beans","Guacamole and totopos","Radish and cucumber salad"],"storage":"Keeps 3 days in the fridge; reheat in a pan with a splash of water to loosen. Freezes well for up to 3 months - crisp again in a hot pan.","chef_upgrade":"Render your own lard from pork back fat - it transforms the depth of flavour. Add a pinch of Mexican oregano and cumin to the fat during confit.","health_forward":"Use pork shoulder with excess fat trimmed, and serve with extra fresh salsa and crisp vegetables. Load tacos with shredded cabbage, radish, and coriander for volume.","diets":["highprotein"],"diet_notes":"Low-carb: serve in lettuce cups with extra salsa. Mediterranean naturally with healthy pork fat and fresh veg."},"chicken-biryani":{"prep":"45 min","cook":"1 hr","mistakes":["Not soaking rice - grains stay hard and separate","Adding rice to boiling stock - must start cold for even cooking","Using too much water - rice becomes mushy","Skipping the dum sealing step - steam escapes and layers dry out"],"sides":["Raita","Brinjal bhaji","Papadums","Lime pickle"],"storage":"Keeps 2 days; reheat gently with a splash of water. The rice continues to absorb moisture - don't over-reheat or grains split.","chef_upgrade":"Make your own ghee and use saffron soaked in warm milk for the top layer. Fried shallots add restaurant-quality depth.","health_forward":"Use skinless chicken thighs and brown the basmati lightly before layering. Increase vegetables and reduce ghee by half - still aromatic.","diets":["highprotein"],"diet_notes":"Mediterranean profile with aromatic spices and lean protein. Low-carb: use cauliflower rice instead of basmati."},"creme-brulee":{"prep":"20 min","cook":"45 min","mistakes":["Overbaking - custard scrambles instead of setting silky","Not straining the custard - egg bits create lumpy texture","Sugar layer too thick - doesn't caramelise evenly","Torching too close - burns sugar before it melts smoothly"],"sides":["Fresh berries","Shortbread biscuits","Espresso"],"storage":"Keeps 2 days in the fridge - sugar softens over time. Add sugar crust just before serving. Undusted custard freezes well for 1 month.","chef_upgrade":"Infuse cream with vanilla bean pod for 4 hours before using. Scrape seeds for maximum flavour - extract lacks complexity.","health_forward":"Use full cream but smaller ramekins (100ml instead of 180ml). Serve with plenty of fresh berries - tart fruit balances rich custard.","diets":[],"diet_notes":"Not diet-friendly as written - indulgence dessert. Mediterranean in spirit but high in saturated fat."},"salmon":{"prep":"5 min","cook":"8 min","mistakes":["Not drying skin - won't crisp properly, stays rubbery","Pan not hot enough - skin sticks and tears","Flipping too soon - skin releases when browned and crisp","Overcooking - salmon turns dry and chalky"],"sides":["Baby potatoes with dill","Steamed asparagus","Lemon wedges"],"storage":"Eat immediately - salmon dries out on reheating. If needed, keep at room temperature up to 2 hours and serve at room temperature with fresh lemon.","chef_upgrade":"Finish with a knob of cold butter and fresh thyme leaves in the brown butter. Serve with micro-cress or watercress for restaurant presentation.","health_forward":"Salmon is already omega-3 rich - serve with double vegetables and skip butter sides. Use capers generously for flavour without added fat.","diets":["med","highprotein"],"diet_notes":"Naturally Mediterranean and high-protein. Low-carb as served - skip potatoes and double the green veg."},"eggs-benedict-hollandaise":{"prep":"30 min","cook":"15 min","mistakes":["Hollandaise too hot or cold - must be warm and emulsified","Not creating whirlpool - egg spreads instead of poaching neatly","Overcooking eggs - yolks must stay runny","Toasting muffins too early - soggy bottoms by assembly time"],"sides":["Asparagus with hollandaise","Roasted baby tomatoes","Hash browns"],"storage":"Eggs and hollandaise don't keep - assemble just before serving. Components can be prepped separately: eggs 1 hour ahead in warm water, hollandaise in thermos.","chef_upgrade":"Clarify your own butter for hollandaise - removes milk solids for purer flavour. Add a drop of truffle oil to finished hollandaise.","health_forward":"Use one egg per muffin instead of two, and load with spinach. Swizzle hollandaise with 25% Greek yoghurt - still creamy but lighter.","diets":["highprotein"],"diet_notes":"High-protein naturally. Mediterranean adaptation: serve on wholegrain toast with avocado and smoked salmon."},"fettuccine-alfredo":{"prep":"10 min","cook":"12 min","mistakes":["Not reserving pasta water - need that starch for emulsion","Adding cheese to cold pan - won't melt smoothly","Using pre-grated cheese - anti-caking agents prevent melting","Overcooking pasta - mushy texture ruins the dish"],"sides":["Garlic bread","Green salad with vinaigrette","Grilled chicken"],"storage":"Best eaten immediately - emulsion breaks on reheating. If needed, undercook pasta slightly and reheat with reserved pasta water and butter.","chef_upgrade":"Make pasta dough fresh - egg and semolina yields silky texture. Finish with aged Parmigiano-Reggiano and white pepper instead of black.","health_forward":"Use half butter, half light philly for protein while keeping creaminess. Load with extra parmesan for flavour - less fat needed.","diets":["highprotein"],"diet_notes":"High-protein with cheese and pasta. Low-carb: use konjac noodles or zucchini ribbons. Mediterranean profile with olive oil swap."},"grilled-calamari":{"prep":"15 min","cook":"8 min","mistakes":["Not patting completely dry - calamari steams instead of searing","Pan not hot enough - no caramelisation, rubbery texture","Overcooking - calamari turns tough and chewy","Not scoring the tubes - thick parts stay raw while thin parts overcook"],"sides":["Lemon wedges","Garlic bread","Greek salad"],"storage":"Eat immediately - calamari toughens on standing. If needed, keep warm in low oven for up to 30 minutes - texture degrades noticeably.","chef_upgrade":"Marinate calamari in lemon zest and olive oil for 30 minutes before cooking. Finish with fresh chilli and rocket for restaurant-style presentation.","health_forward":"Calamari is lean protein - serve with large salad and minimal butter. Use more lemon juice and less butter for brightness.","diets":["highprotein","med"],"diet_notes":"Naturally high-protein and Mediterranean. Low-carb as served - skip bread, double the veg."},"lamb-tagine-apricot-almond":{"prep":"40 min","cook":"1 hr 20 min","mistakes":["Not browning lamb first - lacks deep flavour base","Using lean lamb only - fat keeps meat tender","Adding dried fruit too early - disintegrates completely","Rushing the cooking time - lamb stays chewy"],"sides":["Couscous","Moroccan salad","Flatbreads"],"storage":"Flavours deepen overnight - keeps 3 days. Reheat gently with a splash of water. Freezes well for 3 months - dried fruit texture softens.","chef_upgrade":"Make your own preserved lemon for authentic tang. Use ras el hanout spice blend with toasted cumin and coriander seeds.","health_forward":"Trim lamb fat and add extra vegetables. Use smaller amount of dried fruit and more fresh apricots if in season. Serve with plenty of couscous and salad.","diets":["highprotein"],"diet_notes":"High-protein with lamb. Mediterranean profile naturally. Low-carb: serve over cauliflower rice or with extra veg."},"lasagne-bolognese":{"prep":"1 hr","cook":"1 hr 30 min","mistakes":["Ragù too wet - soggy layers","Not resting lasagne before slicing - falls apart","Béchamel too thick - gluey texture","Using no-boil pasta sheets without adjusting liquid - dry spots"],"sides":["Garlic bread","Green salad"],"storage":"Better next day - flavours meld, keeps 4 days. Reheat uncovered at 180°C for 20 minutes. Freezes uncut for 3 months - texture holds well.","chef_upgrade":"Make fresh pasta sheets - tender and absorbs sauce perfectly. Slow-cook ragù for 4 hours and use veal-pork-beef mix for authentic depth.","health_forward":"Lean beef mince and add grated carrot and courgette to ragù for volume. Use whole wheat pasta and increase vegetable layers.","diets":["highprotein"],"diet_notes":"High-protein with cheese and meat. Low-carb: replace pasta sheets with sliced aubergine or use konjac lasagne sheets."},"molten-chocolate-fondant":{"prep":"15 min","cook":"12 min","mistakes":["Overbaking by 2 minutes - centre sets solid","Not brushing moulds thoroughly with butter - fondants stick","Using cold eggs - butter solidifies and creates streaks","Not resting moulds before unmoulding - fondants collapse"],"sides":["Crème fraîche","Raspberries","Espresso"],"storage":"Bake just before serving - centres set completely on cooling. Batter can be made 24 hours ahead and chilled - bring to room temperature before baking.","chef_upgrade":"Use 70% Valrhona or Lindt chocolate for depth. Add a splash of Grand Marnier and orange zest to batter - next-level restaurant touch.","health_forward":"Use small moulds (100ml) for portion control. Dark chocolate 70%+ has antioxidants - serve with fresh berries rather than cream.","diets":[],"diet_notes":"Indulgence dessert, not diet-friendly. Dark chocolate has antioxidants but high in saturated fat and sugar."},"mussels-white-wine-garlic":{"prep":"15 min","cook":"8 min","sides":["Crusty bread for mopping up the liquor","Simple green salad with vinaigrette","French fries"],"storage":"Best eaten immediately. Cool and refrigerate within 2 hours of cooking; keeps 1 day. Reheat gently over low heat just until steamed — do not boil or mussels will toughen.","chef_upgrade":"Finish with a compound butter of softened butter mixed with fines herbes (chives, parsley, tarragon, chervil) and a pinch of flaky sea salt, dotting it over the mussels just as they steam open.","health_forward":"Use half the butter and boost with extra shallots and garlic; serve with a generous green salad and limit bread to one slice per person.","diets":["med","highprotein"],"diet_notes":"Naturally low-carb and protein-rich; suitable for Mediterranean-style eating. For plant-based, substitute mussels with king oyster mushrooms and use vegetable stock."},"moussaka":{"prep":"45 min","cook":"1 hr 15 min","sides":["Greek salad with feta and olives","Crusty bread","Roasted baby marrow with lemon and oregano"],"storage":"Keeps 3 days refrigerated; the flavours deepen. Reheat uncovered at 180°C for 20-25 minutes until bubbly. Freezes well for up to 2 months; thaw overnight before reheating.","health_forward":"Lighten by grilling or brushing aubergine slices with less oil instead of frying; use lean beef mince and reduce béchamel butter by half.","diets":["med","highprotein"],"diet_notes":"Naturally gluten-containing due to flour in béchamel. For plant-based, substitute beef mince with lentils or plant-based mince and use a cheese-free béchamel or vegan cheese alternative.","chef_upgrade":"Salt, drain and press the aubergine slices, then grill-brush with oil rather than shallow-fry for a grease-free, silky layer; loosen the bechamel with grated Parmesan (or kefalotyri) and an egg yolk so the top sets golden and sliceable; rest 20 min before portioning so the layers hold their shape on the plate."},"peri-peri-chicken-livers":{"health_forward":"Reduce cream to 60ml and add 2 tablespoons plain yoghurt for acidity and lower fat; serve with a side of grilled mixed peppers and extra spring onions.","diets":["highprotein","lowcarb"],"diet_notes":"Naturally low-carb if serving with vegetables instead of bread. Suitable for high-protein diets. For plant-based, substitute chicken livers with firm tofu or tempeh and use plant-based cream."},"pizza-margherita":{"health_forward":"Use a thin wholegrain or cauliflower crust; boost mozzarella to 200g and reduce added oil; serve with a large side salad.","diets":["med","plant"],"diet_notes":"Naturally vegetarian. For lower-carb, use a thin crust or cauliflower base and limit portion size. For plant-based, use vegan mozzarella."},"potato-gnocchi":{"health_forward":"Use half butter and finish with a splash of pasta water; add 100g frozen peas or chopped spinach during the final minute.","diets":["med","plant"],"diet_notes":"Naturally vegetarian and suitable for plant-based eating. For lower-carb, substitute with cauliflower gnocchi or courgetti and use the same sage butter."},"risotto-milanese-saffron":{"prep":"10 min","cook":"25 min","sides":["Grilled asparagus or green beans","Simple arugula salad with shaved parmesan","Roasted vine tomatoes"],"storage":"Best eaten immediately — risotto texture degrades quickly. Cool and refrigerate within 2 hours; keeps 2 days. Reheat gently with a splash of stock, stirring constantly — it won't be quite as creamy.","chef_upgrade":"Use homemade bone-rich chicken stock and finish with a 20g knob of cold butter and 40g aged parmesan, off the heat, whipped vigorously for an emulsified glossy finish.","health_forward":"Use half butter and reduce parmesan by 30g; bulk with extra vegetables (peas, asparagus tips) during the final 3 minutes.","diets":["med"],"diet_notes":"Naturally gluten-containing. For plant-based, use vegetable stock and substitute parmesan with nutritional yeast or vegan parmesan."},"roast-chicken":{"prep":"20 min","cook":"1 hr 20 min","mistakes":["Not bringing chicken to room temperature before roasting (leads to uneven cooking)","Overcooking until dry — aim for 74°C breast temperature","Not resting the chicken (juices run out instead of redistributing)","Crowding the roasting pan (prevents browning)"],"sides":["Roast potatoes with rosemary and garlic","Green beans with lemon and almonds","Grilled mielie with paprika","Simple gravy from pan drippings"],"storage":"Keeps 4 days refrigerated. Carve and store in portions; reheat uncovered at 160°C for 15-20 minutes until warmed through. Freezes well for up to 2 months.","chef_upgrade":"Dry-brine the chicken 24 hours before roasting (1 tbsp salt per kg, refrigerated uncovered) for crispest skin and deepest flavour; baste with butter and pan juices every 20 minutes.","health_forward":"Remove skin before eating; reduce butter by half and stuff cavity with extra lemon and herbs; serve with generous vegetables.","diets":["med","highprotein"],"diet_notes":"Naturally gluten-free. Suitable for Mediterranean and high-protein diets."},"rogan-josh":{"prep":"45 min","cook":"2 hr","storage":"Keeps 4 days refrigerated; the flavours deepen. Reheat gently over low heat, adding a splash of water if needed. Freezes well for up to 3 months.","chef_upgrade":"Marinate lamb overnight in yoghurt and ginger paste; use freshly toasted and ground whole spices (fennel, cumin, cardamom) instead of pre-ground.","health_forward":"Trim excess fat from lamb; use half the ghee and bulk with extra tomatoes or butternut cubes added during the final hour.","diets":["highprotein"],"diet_notes":"Naturally gluten-free. Suitable for high-protein diets. For plant-based, substitute lamb with firm tofu or tempeh and use plant-based yoghurt."},"sticky-toffee-pudding":{"prep":"30 min","cook":"45 min","sides":["Clotted cream, ice cream, or custard","Caramelised orange segments","Strong black coffee","Simple berry compote"],"storage":"Keeps 3 days at room temperature, 5 days refrigerated (warm before serving). Sauce keeps 1 week refrigerated; reheat gently with a splash of cream. Freezes well for 2 months — thaw overnight.","chef_upgrade":"Use medjool dates for deeper caramel flavour; infuse sauce with a split vanilla pod and finish with 2 tablespoons dark rum or whisky.","health_forward":"Replace half sugar with mashed banana; reduce sauce cream by half and serve with yoghurt or portion control.","diets":[],"diet_notes":"Contains dairy and gluten. For plant-based, substitute butter with plant-based alternative and use plant-based cream and yoghurt."},"tiramisu":{"prep":"30 min","cook":"20 min + chill","mistakes":["Over-soaking ladyfingers (creates a soggy, wet layer)","Using watery mascarpone (curdles when whipped)","Not chilling long enough (texture is soft, not set)","Using stale coffee (bitter, flat flavour)"],"sides":["Espresso or strong coffee","Dark chocolate shavings","Simple fresh berries"],"storage":"Keeps 3 days refrigerated, covered. Best served within 24 hours as ladyfiddles soften further. Do not freeze (texture degrades).","chef_upgrade":"Use freshly grated Parmigiano-Reggiano in the mascarpone cream for depth; finish with 60% dark chocolate shavings and a dusting of high-quality cocoa.","health_forward":"Use half sugar and add 1 teaspoon vanilla extract; reduce ladyfingers by 2 and bulk with extra whipped egg whites folded in.","diets":["highprotein"],"diet_notes":"Contains raw eggs and dairy; not suitable for plant-based, gluten-free, or low-sugar diets as written."},"braai-lamb-chops-chimichurri":{"prep":"25 min","cook":"15 min","mistakes":["Over-marinating makes lamb mushy — 2 hours max","Chimichurri loses freshness if made more than 4 hours ahead","Flaring grease burns the herbs — keep oil lightly brushed","Skipping rest time makes juices run onto the plate","Not scraping grill leaves bitter char on next batch"],"sides":["Creamed spinach with nutmeg","Roasted baby potatoes with rosemary","Grilled sweetcorn with chilli butter","Fresh green salad with vinaigrette"],"storage":"Chimichurri keeps 3 days refrigerated; lamb best eaten fresh but keeps 2 days — reheat gently in a low oven. Separate sauce before reheating meat.","chef_upgrade":"Dry-age lamb 48 hours in the fridge uncovered for intensified flavour and better crust, or splurge on Karoo lamb for that distinctive herbal terroir.","health_forward":"Trim excess fat before grilling and serve chimichurri on the side for control — the fresh herbs pack antioxidants and the lamb provides high-quality protein.","diets":["highprotein","med"],"diet_notes":"Low-carb as written; serve with roasted veg instead of potatoes. For lighter version, use leg instead of chops and reduce basting."},"coq-au-vin":{"prep":"35 min","cook":"1 hr 40 min","sides":["Crusty baguette for mopping sauce","Buttered parsley noodles","Creamy mashed potato","Braised red cabbage with apple"],"storage":"Keeps 3 days refrigerated; actually improves overnight as flavours meld. Reheat gently with a splash of stock or water. Freeze up to 3 months — the wine protects the texture.","chef_upgrade":"Make your own chicken stock from wings and veg for deeper flavour base, or marinate chicken overnight in the wine for deep flavour penetration.","health_forward":"Serve more veg and less bread; skin chicken to reduce saturated fat while keeping the soul. The wine-braised vegetables are nutrient-dense.","diets":["highprotein","med"],"diet_notes":"Low-carb if you skip the bread and potatoes; the wine sauce has minimal carbs. Plant-forward version: use mushrooms and pearl onions as the protein, or swap in firm tofu."},"duck-a-l-orange":{"prep":"30 min","cook":"2 hr","sides":["Roasted baby potatoes with duck fat","Glazed carrots with thyme","Watercress salad with mustard dressing","Steamed green beans with garlic"],"storage":"Duck keeps 3 days refrigerated; sauce keeps 5 days. For best results, store separately and reheat duck at 180°C until crisped, then warm sauce gently. Freezes well for 2 months.","chef_upgrade":"Render the fat slowly and confit the legs in it for 3 hours before roasting — restaurant luxury at home. The drippings make the best potatoes.","health_forward":"Duck fat is stable and flavourful; use it sparingly. The sauce's sharp orange cuts richness. Serve with more bitter greens to balance.","diets":["highprotein"],"diet_notes":"Not low-carb due to sugar in sauce, but protein-rich. For lighter version, reduce sugar in sauce and serve with steamed veg."},"mozambican-peri-peri-chicken":{"prep":"30 min","cook":"45 min","sides":["Fluffy yellow rice","Grilled sweetcorn with chilli butter","Fresh tomato and onion salad","Roasted sweet potato wedges"],"storage":"Marinated chicken keeps 2 days refrigerated; cooked leftovers keep 3 days and freeze for 2 months. Sauce keeps 2 weeks — it's excellent on everything.","chef_upgrade":"Grill over charcoal for authentic smoky depth, or butterfly the chicken for faster, more even cooking and crispy skin all over.","health_forward":"Chicken thighs provide iron and B12; the chilli boosts metabolism. Use less oil in the baste and serve with extra veg — a salad with avocado cuts the heat beautifully.","diets":["highprotein","med"],"diet_notes":"Low-carb if you skip rice and serve with roasted veg or salad. Plant-forward version: use cauliflower steaks or portobello mushrooms — they soak up the peri-peri brilliantly."},"steak":{"prep":"5 min","cook":"13 min","mistakes":["Not salting early enough — salt at least 1 hour ahead for interior seasoning","Pan not hot enough — steak stews instead of sears","Flipping too often — one flip, maybe two","Crowding the pan lowers temperature","Resting less than 5 minutes makes juices run out"],"sides":["Crispy frites with garlic aioli","Creamed spinach","Charred broccolini with lemon","Roasted baby potatoes with rosemary"],"storage":"Eat immediately — steak overcooks on reheating. If you must, keep rare and finish quickly in a hot pan. Never freeze cooked steak.","chef_upgrade":"Dry-age the meat 48 hours uncovered for intensified flavour, or finish with a compound butter of anchovy, garlic, and parsley for cafe de paris luxury at home.","health_forward":"Choose rump or sirloin over ribeye for less saturated fat; the baste adds richness without excess oil. Pair with bitter greens.","diets":["highprotein","lowcarb","med"],"diet_notes":"Perfect low-carb meal with just veg. For lighter version, choose leaner cut and use less butter in the baste."},"lamb-shank-red-wine":{"prep":"30 min","cook":"2 hr 30 min","sides":["Creamy polenta with parmesan","Buttered mash","Braised red cabbage","Roasted root vegetables"],"storage":"Best made ahead — keeps 4 days refrigerated and actually improves. Reheat gently with a splash of stock. Freezes beautifully for 3 months.","chef_upgrade":"Brown the shanks aggressively for deep flavour base, or add a glug of port and dried figs in the last hour for sticky luxury.","health_forward":"Lamb shank is iron-rich and collagen-packed for joint health. Serve with more veg and less starch; the long braise makes nutrients bioavailable.","diets":["highprotein","med"],"diet_notes":"Low-carb if you serve with roasted veg instead of polenta. Plant-forward version: use king oyster mushrooms or artichoke hearts — they braise beautifully."},"red-wine-braised-short-rib":{"prep":"30 min","cook":"3 hr 30 min","mistakes":["Not searing hard enough — pale meat lacks depth foundation","Crowding the pan steams instead of browns","Skipping the reduction makes thin, bland sauce","Rushing cook time leaves meat tough, not melting","Not skimming fat leaves sauce greasy"],"sides":["Creamy mashed potato","Roasted root vegetables with thyme","Charred kale with garlic","Buttered egg noodles"],"storage":"Short ribs improve with a day — the fat renders and flavours meld. Keeps 4 days refrigerated, 3 months frozen. Reheat gently with a splash of stock.","chef_upgrade":"Make a rich beef bone stock as the base, or add a touch of espresso and dark chocolate in the final sauce for depth.","health_forward":"Short ribs are collagen-rich for joint health but high in fat — trim excess and skim sauce thoroughly. The wine adds antioxidants.","diets":["highprotein"],"diet_notes":"Not low-carb if served with potatoes; go for roasted veg or cauliflower mash. For lighter version, use beef shin instead."},"sosaties":{"prep":"45 min","cook":"45 min","sides":["Yellow rice with turmeric","Roasted sweet potato wedges","Tomato and onion sambal","Creamed spinach"],"storage":"Marinate up to 24 hours; cooked sosaties keep 3 days refrigerated. Reheat gently in a low oven or serve cold in salads. Freeze uncooked for 1 month.","chef_upgrade":"Wrap each apricot in bacon before skewering for smoky-sweet luxury, or grill over proper coals for that authentic Cape Town flavour.","health_forward":"Lamb provides iron and B12; dried apricots add fibre. Use lean leg meat and less sugar in the marinade. Serve with extra veg.","diets":["highprotein","med"],"diet_notes":"Moderate carb from apricots and marinade. For lower carb, use fewer apricots and more onion. Plant version: use chicken or pineapple chunks."},"steak-frites-cafe-de-paris":{"prep":"20 min","cook":"30 min","sides":["Mixed green salad with vinaigrette","Roasted tomatoes with garlic","Steamed asparagus with lemon","Buttered peas with mint"],"storage":"Steak is best eaten immediately; frites lose crunch on storage. Compound butter keeps 2 weeks refrigerated, 3 months frozen. Reheat frites in a hot oven.","chef_upgrade":"Double-fry the frites — once at 150°C to cook through, then at 190°C for crispness. Or make your own butter with fresh herbs and sea salt.","health_forward":"Ribeye is rich; choose sirloin for less saturated fat. The butter is flavour-heavy, so use sparingly. Serve with more greens.","diets":["highprotein"],"diet_notes":"Not low-carb or light — this is indulgent. For slightly lighter, choose leaner cut and less butter. Fries are the carb bomb here."},"koeksisters":{"prep":"40 min","cook":"20 min","sides":["Strong tea","Fresh coffee","Vanilla ice cream","Greek yoghurt with berries"],"storage":"Koeksisters are best fresh — the syrup crystalizes over time. Keeps 2 days in an airtight container. Freeze uncooked dough for 1 month; fry from frozen.","chef_upgrade":"Infuse the syrup with star anise and cardamom for spiced depth, or roll in toasted coconut after dipping for texture contrast.","health_forward":"This is a treat — small portions only. The syrup is pure sugar; enjoy occasionally with protein to slow absorption.","diets":[],"diet_notes":"Not suitable for restricted diets — this is pure indulgence. For slightly lighter, roll in thinner plaits and dip for less time."},"malva-pudding":{"prep":"15 min","cook":"45 min","mistakes":["Over-baking leads to dry sponge - check at 35 min and remove when just set","Sauce poured cold creates a soggy pudding - it must be bubbling hot","Opening oven too early causes collapse - the steam lift is essential","Using margarine instead of butter in sauce misses the caramel depth","Not letting the pudding rest 10 min after saucing means the sauce won't soak through properly"],"sides":["Custard (vanilla or almond)","Vanilla ice cream","Fresh cream","Crisp bacon for salty contrast"],"storage":"Keeps 3 days refrigerated, covered. Reheat in microwave 30-60 seconds per portion or oven at 150C for 10-15 min. Sauce thickens when chilled - thin with 1-2 tbsp cream and gently warm before serving.","chef_upgrade":"Infuse the cream with 5-6 crushed cardamom pods and 1 cinnamon stick for 15 min before whisking into butter and sugar - subtle warm spices lift the apricot jam.","health_forward":"Swap half the sugar for xylitol or erythritol and use 30g less butter in the sauce, or replace half the flour with almond flour for lower GI and added protein.","diets":[],"diet_notes":"Not naturally diet-friendly - treat as occasional dessert. For lighter version, serve smaller portions with fresh berries."},"potjiekos":{"prep":"30 min","cook":"2 hr","sides":["Brown rice","Pap (mielie meal) or samp","Green salad with vinaigrette","Roasted vegetables"],"storage":"Keeps 4 days refrigerated - flavours improve. Freeze up to 3 months in portions. Reheat gently on stovetop with 2-3 tbsp water or stock, covered - don't boil hard or meat toughens.","chef_upgrade":"Make a rich homemade beef stock from roasted bones and aromatics, reduce by half before adding - depth you can't buy.","health_forward":"Use leaner lamb leg instead of neck, add double the beans and cabbage, serve with brown rice instead of pap for more fibre and less saturated fat.","diets":["med","highprotein"],"diet_notes":"Low-carb: skip potatoes and serve with cauli-rice or extra green beans. Plant-forward: replace lamb with butternut, aubergine and chickpeas, use vegetable stock."},"beef-ribs-sticky-braise":{"health_forward":"Trim visible fat before braising, swap brown sugar for xylitol, serve with plenty of roasted vegetables and skip the second glaze for less sugar.","diets":["med","highprotein"],"diet_notes":"Low-carb: double the carrots and onions, skip the final glaze or use pure stevia. Not plant-forward - heavy meat dish."},"espetada":{"health_forward":"Use rump steak instead of sirloin, add extra mushrooms and cubes of red capsicum between meat, grill without butter finish.","diets":["med","highprotein"],"diet_notes":"Low-carb: excellent as-is, just skip bread. Plant-forward: use halloumi cubes or thick mushroom caps instead of beef."},"roast-leg-lamb-rosemary-garlic":{"prep":"20 min","cook":"1 hr 40 min","mistakes":["Overcooking - medium-rare is 60C, medium 65C, anything past 70C is tough","Not resting at least 15 min means juices run out onto carving board instead of staying in the meat","Slashing too deep lets juices escape during cooking - surface cuts only","Seasoning only at the end means salt never penetrates - season at least 2 hrs before or overnight","Using dried rosemary instead of fresh loses the piney brightness that cuts the fat"],"sides":["Roasted potatoes with garlic","Green beans with almonds","Mint sauce (fresh mint, vinegar, sugar)","Grilled aubergine with yoghurt"],"storage":"Keeps 4 days refrigerated, 3 months frozen. Slice cold for sandwiches or salads. Reheat gently in oven at 150C for 10-15 min, covered - don't boil.","chef_upgrade":"Dry-brine overnight (1 tbsp coarse salt per kg lamb, rubbed in and refrigerated uncovered) for deeper seasoning and crisper skin.","health_forward":"Trim all external fat, roast on a bed of carrots and onions instead of a rack, serve with extra vegetables and a fresh green salad.","diets":["med","highprotein"],"diet_notes":"Low-carb: skip potatoes, double roasted veg. Plant-forward: portobello mushrooms or cauliflower steaks with rosemary-garlic oil."},"boerewors":{"prep":"40 min","cook":"15 min","storage":"Keeps 3 days refrigerated, 3 months frozen. Freeze raw or cooked in portions. Reheat gently on low heat in pan - don't boil or casing splits.","chef_upgrade":"Cold-smoke over rooibos wood chips for 2-3 hrs after initial grilling for subtle smoky depth.","health_forward":"Use leaner beef (5-10% fat instead of 15-20%), add more coriander and garlic for flavour, serve with extra chakalaka and salad instead of bread rolls.","diets":["highprotein"],"diet_notes":"Not plant-forward - sausage is meat-heavy. For lighter, serve smaller portions and pile on vegetable sides."},"chakalaka":{"prep":"15 min","cook":"25 min","sides":["Boerewors or braai meat","Pap or bread","Green salad","Cottage cheese or yoghurt"],"storage":"Keeps 1 week refrigerated - flavours meld. Freeze up to 3 months. Reheat gently in pan with 1-2 tbsp water, covered.","chef_upgrade":"Char the capsicum and carrots over coals or under grill before simmering - smoky sweetness balances the curry heat.","health_forward":"Halve the oil, use baking beans in tomato sauce with no added sugar, add extra grated carrots and butternut for sweetness without sugar.","diets":["plant"],"diet_notes":"Already plant-forward. Mediterranean: add more olive oil and olives. High-protein: serve with grilled meat or add chickpeas."},"focaccia":{"prep":"20 min","cook":"20 min","sides":["Tomato bruschetta","Olive tapenade","Caprese salad","Garlic and herb dip"],"storage":"Keeps 2 days at room temperature in paper bag - plastic makes it soggy. Freeze up to 1 month, thaw and refresh at 180C for 5 min. Don't refrigerate - stale within hours.","chef_upgrade":"Use biga starter (100g flour, 100g water, pinch yeast, fermented 12-16 hrs) for deeper flavour and longer shelf life.","health_forward":"Replace 30% flour with whole-wheat flour, use extra-virgin olive oil generously, top with more fresh herbs and less salt.","diets":["med","plant"],"diet_notes":"Low-carb: not suitable - refined flour base. High-protein: serve with chickpea dip or alongside grilled fish."},"mealie-bread":{"prep":"20 min","cook":"40 min","mistakes":["Over-mixing develops gluten - fold until just combined, some lumps are fine","Opening oven before 25 min collapses the structure - steam lift is crucial","Using all-purpose flour instead of cake flour makes it tough","Sugar instead of golden syrup or honey loses the caramel depth","Not testing doneness at 35 min - it continues cooking in the pan"],"sides":["Boerewors or braai meat","Tomato relish or chakalaka","Cream cheese","Butter and apricot jam"],"storage":"Keeps 3 days at room temperature in airtight container, 1 week refrigerated. Freeze up to 3 months, thaw and reheat at 160C for 10 min. Serve warm.","chef_upgrade":"Grill fresh mealie ears over coals until charred, cut kernels off and fold into batter - smoky sweetness.","health_forward":"Swap half cake flour for whole-wheat flour, reduce sugar by 1/3, add extra mealies for fibre, serve with protein-rich sides like grilled fish or beans.","diets":["plant"],"diet_notes":"Low-carb: not suitable - corn and flour base. Mediterranean: drizzle with olive oil and serve with feta."},"naan-bread":{"prep":"20 min","cook":"5 min per batch","mistakes":["Not rolling thin enough means doughy centre - aim for 3-4mm","Cooking on too low heat won't bubble and char - pan must be smoking hot","Pressing down with spatula after flipping traps steam and makes it soggy","Skipping yoghurt makes it tough - it tenderises gluten","Not covering cooked naan keeps it from steaming soft - stack and wrap in cloth"],"storage":"Keeps 1 day at room temperature in cloth, 3 days refrigerated. Freeze up to 2 months with baking paper between pieces. Reheat in hot pan 30 seconds per side.","chef_upgrade":"Brush with garlic butter (3 cloves garlic, 100g butter, melted) immediately after cooking and sprinkle with fresh coriander.","health_forward":"Use whole-wheat flour for half, reduce butter brushing, serve with bean-based curries and extra vegetables.","diets":["plant"],"diet_notes":"Low-carb: not suitable - refined flour. High-protein: serve with lentil dhal or chickpea curry.","sides":["Butter chicken or lamb curry","Dhal or tikka masala","Tandoori chicken or seekh kebabs","Melted garlic butter and fresh coriander"]},"pap":{"prep":"5 min","cook":"25 min","mistakes":["Adding mealie meal to boiling water causes lumps - mix with cold water first","Not stirring enough leads to burning at the bottom","Too much water makes pap soggy and weak","Too little water makes pap stiff and dry","Wrong consistency for the dish - phutu should be crumbly, slap pap should be smooth"],"sides":["Tomato and onion relish","Braai meat or wors","Chakalaka","Morogo (spinetach)"],"storage":"Keeps 2-3 days refrigerated. Reheat with a splash of water or milk in a pot, stirring constantly to prevent lumps. Can be frozen for up to 1 month - thaw completely before reheating.","chef_upgrade":"Toast the mealie meal in a dry pan until fragrant before cooking - adds a nutty depth. Stir in a knob of butter at the end for richness.","health_forward":"Use half mealie meal half maize bran for more fibre, or swap to brown maize meal if available. Still delivers the authentic texture with more nutrients.","diets":["plant"],"diet_notes":"Naturally plant-based. For higher protein, serve with beans or legumes. Not suitable for low-carb or keto due to high starch content."},"potbrood":{"prep":"20 min","cook":"1 hr 30 min","mistakes":["Water too hot kills the yeast - use lukewarm, not hot","Under-proving leads to dense, heavy bread","Baking at too high heat burns the outside before the inside cooks","Not greasing the pot well enough causes sticking","Opening the lid too often loses heat and creates a dense loaf"],"sides":["Braai meat and wors","Braaied corn on the cob","Tomato bredie","Pap and gravy"],"storage":"Keeps 2-3 days at room temperature in a sealed bag, or up to 5 days refrigerated. Freeze for up to 3 months. Best served fresh but reheats well wrapped in foil in a 180C oven for 10 minutes.","chef_upgrade":"Use a sourdough starter instead of yeast for deeper flavour and longer keeping. Brush the top with melted butter mixed with garlic and herbs immediately after baking for a fragrant golden crust.","health_forward":"Replace up to half the bread flour with wholewheat flour for more fibre and nutrients. Still creates a soft loaf with a nuttier flavour.","diets":["plant"],"diet_notes":"Naturally plant-based as written. For added protein, serve with beans or cheese. Not suitable for low-carb due to high flour content."},"roosterkoek":{"prep":"15 min","cook":"30 min","mistakes":["Dough too wet sticks to everything and burns easily","Not proving long enough makes flat, dense bread","Coals too hot burn the outside before the inside cooks","Flipping too often prevents proper crust formation","Not oiling the grid causes sticking and tearing"],"sides":["Braai meat or wors","Braaied mielie","Tomato and onion salad","Chakalaka"],"storage":"Best eaten immediately off the braai. Keeps 1-2 days in a sealed bag - reheat on a hot grid or toast. Can be frozen for up to 1 month; thaw and reheat on a hot pan.","chef_upgrade":"Brush with garlic butter immediately after coming off the grid, or stuff with cheese and spring onion halfway through cooking. A dusting of coarse sea salt while hot adds a professional finish.","health_forward":"Use half wholewheat flour for more fibre and a nuttier flavour. Replace some flour with seeds for added protein and crunch.","diets":["plant"],"diet_notes":"Naturally plant-based. Stuff with grilled vegetables for more nutrients. Not suitable for low-carb diets due to high flour content."}});
